 1	import React, { FC } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { startTour } from '@kubevirt-utils/components/GuidedTour/utils/constants';
 5	import { ALL_NAMESPACES, ALL_NAMESPACES_SESSION_KEY } from '@kubevirt-utils/hooks/constants';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 8	import { Button, ButtonVariant, Split, SplitItem } from '@patternfly/react-core';
 9	import { ExternalLinkAltIcon } from '@patternfly/react-icons';
10	
11	type WelcomeButtonsProps = {
12	  onClose: () => Promise<void> | void;
13	};
14	
15	const WelcomeButtons: FC<WelcomeButtonsProps> = ({ onClose }) => {
16	  const { t } = useKubevirtTranslation();
17	  const [activeNamespace] = useActiveNamespace();
18	  const navigate = useNavigate();
19	  const namespace =
20	    activeNamespace === ALL_NAMESPACES_SESSION_KEY ? ALL_NAMESPACES : `ns/${activeNamespace}`;
21	
22	  return (
23	    <Split hasGutter>
24	      <SplitItem>
25	        <Button
26	          onClick={() => {
27	            navigate(`/k8s/${namespace}/catalog`);
28	            onClose();
29	          }}
30	          className="WelcomeModal__button"
31	          variant={ButtonVariant.primary}
32	        >
33	          {t('Create VirtualMachine')}
34	        </Button>
35	      </SplitItem>
36	      <SplitItem>
37	        <Button
38	          onClick={() => {
39	            startTour();
40	            onClose();
41	          }}
42	          className="WelcomeModal__button"
43	          variant={ButtonVariant.secondary}
44	        >
45	          {t('Start Tour')}
46	        </Button>
47	      </SplitItem>
48	      <SplitItem isFilled />
49	      <SplitItem>
50	        <Button
51	          onClick={() => {
52	            navigate(`/k8s/${namespace}/virtualization-overview`);
53	            onClose();
54	          }}
55	          className="WelcomeModal__button"
56	          icon={<ExternalLinkAltIcon />}
57	          iconPosition="end"
58	          variant={ButtonVariant.link}
59	        >
60	          {t('Getting started resources')}
61	        </Button>
62	      </SplitItem>
63	    </Split>
64	  );
65	};
66	
67	export default WelcomeButtons;

